// Transform: HubSpot payload -> ERPNext issue_order payload.
// Input: webhook recebe { body: { hubspot_deal_id, companies[], contacts[], products[] } }
// Output: { hubspot, customer, prescribers, patients, items, fp_patients }

const items = $input.all();
const out = [];

for (const item of items) {
  const body = item.json.body || item.json;

  const dealId = String(body.hubspot_deal_id || '');
  const companies = body.companies || [];
  const contacts = body.contacts || [];
  const products = body.products || [];

  // ---- Customer (da primeira company) ----
  const co = companies[0] || {};
  const cnpjDigits = (co.cnpj || '').replace(/\D/g, '');
  const cpfRespDigits = (co.cpf_responsavel || '').replace(/\D/g, '');
  const isCompany = !!cnpjDigits;
  const customer = {
    customer_name: co.name || 'Cliente Sem Nome',
    customer_type: isCompany ? 'Company' : 'Individual',
    tax_id: cnpjDigits || cpfRespDigits || '',
  };

  // ---- Helper: gera CPF placeholder do médico a partir de CRM+UF ----
  // HubSpot não envia CPF do médico; CPF é único no Prescriber.
  // Gera CPF determinístico baseado em (crm + uf) pra idempotência.
  function medicoCpfStub(crm, uf) {
    const s = (String(crm || '') + (uf || '')).replace(/\D/g, '').padStart(11, '0');
    const base = s.slice(0, 11).padStart(11, '0');
    if (base === base[0].repeat(11)) return base.slice(0, 10) + '9';
    return base;
  }

  // ---- Agrupa prescribers (médicos) e patients (pacientes) únicos ----
  const prescribersMap = new Map();
  const patientsMap = new Map();
  const fpPatients = [];
  const itemsMap = new Map();

  for (const p of products) {
    const sku = String(p.sku || '');
    const qty = Number(p.quantidade || p.quantity || 1);
    const rate = Number(p.price || 0);

    if (itemsMap.has(sku)) {
      itemsMap.get(sku).qty += qty;
    } else {
      itemsMap.set(sku, { item_code: sku, qty: qty, rate: rate, warehouse: 'Produtos Acabados - I' });
    }

    const crm = String(p.medico_crm || '');
    const uf = String(p.medico_uf || '');
    const medCpf = medicoCpfStub(crm, uf);
    if (!prescribersMap.has(medCpf)) {
      prescribersMap.set(medCpf, {
        cpf: medCpf,
        full_name: p.medico_nome || ('Medico ' + crm + '-' + uf),
        councils: [{
          council_type: 'CRM',
          council_number: crm,
          council_state: uf || 'SP',
          council_status: 'Ativo',
          is_primary: 1,
        }],
      });
    }

    const patCpf = (p.cpf || '').replace(/\D/g, '');
    if (patCpf && !patientsMap.has(patCpf)) {
      patientsMap.set(patCpf, {
        cpf: patCpf,
        patient_name: p.nome || 'Paciente Sem Nome',
        gender: p.genero || 'Outro',
        mobile: p.telefone || '',
        default_prescriber_cpf: medCpf,
      });
    }

    fpPatients.push({
      patient_cpf: patCpf,
      prescriber_cpf: medCpf,
      prescriber_council: { council_type: 'CRM', council_number: crm, council_state: uf || 'SP' },
      item_code: sku,
      qty: qty,
    });
  }

  out.push({
    json: {
      hubspot: { deal_id: dealId, contact_id: contacts[0]?.email || '' },
      customer: customer,
      prescribers: Array.from(prescribersMap.values()),
      patients: Array.from(patientsMap.values()),
      items: Array.from(itemsMap.values()),
      fp_patients: fpPatients,
      company: 'Injmedpharma',
    },
  });
}

return out;
